def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif 0.5 <= ratio <= 1:
            priorities[i] = np.exp(ratio) - 1
        else:
            sum_val = 0
            for j in range(1, 6):
                if ratio == 0:
                    term = 0
                else:
                    term = (ratio ** j) / np.math.factorial(j)
                sum_val += term
            priorities[i] = 1 / (sum_val + 1e-5)
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for k in range(len(priorities)):
        if np.isinf(priorities[k]):
            priorities[k] = max_priority * 10
    return priorities
